cte2 AS (SELECT c.id,c.name,c.segment,CASE WHEN c.ltv>100000 THEN 'PLATINUM' WHEN c.ltv>50000 THEN 'GOLD' WHEN c.ltv>10000 THEN 'SILVER' ELSE 'BRONZE' END AS seg,DENSE_RANK() OVER(ORDER BY c.ltv DESC) AS dr,ROW_NUMBER() OVER(PARTITION BY c.segment ORDER BY c.ltv DESC) AS seg_rnk FROM PROD_DB..CUSTOMERS_3 c WHERE c.active=TRUE),
cte3 AS (SELECT r.id,r.name AS reg,cte1.rev,cte1.rnk,cte2.seg,cte2.name AS cname,cte2.seg_rnk,LAG(cte1.rev) OVER(PARTITION BY r.id ORDER BY cte1.rev) AS prev_rev,LEAD(cte1.rev) OVER(PARTITION BY r.id ORDER BY cte1.rev) AS next_rev,NTILE(4) OVER(ORDER BY cte1.rev DESC) AS qtl FROM PROD_DB..REGIONS_0 r JOIN cte1 ON r.id=cte1.category LEFT JOIN cte2 ON cte1.id=cte2.id WHERE r.active=TRUE AND r.is_available=TRUE)
SELECT reg,cname,seg,rev,COALESCE(prev_rev,0) AS prev_rev,COALESCE(next_rev,0) AS next_rev,CASE WHEN rev>=1000000 THEN 'OUTSTANDING' WHEN rev>=500000 THEN 'EXCELLENT' WHEN rev>=100000 THEN 'GOOD' WHEN rev>=10000 THEN 'AVERAGE' ELSE 'LOW' END AS perf_cat,rev-COALESCE(prev_rev,0) AS revenue_change,ROUND(rev/NULLIF(rnk,1),2) AS avg_per_order,CONCAT(reg,'-',seg) AS compound_key FROM cte3 WHERE qtl<=3 AND rev>0 ORDER BY rev DESC,seg_rnk ASC LIMIT 500;

